const items = $input.all();
const seen = new Set();
const now = new Date();
const sevenDaysAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
const filtered = [];

for (const item of items) {
  const d = item.json;
  const title = d.title || d.headline || '';
  const link = d.link || d.url || d.guid || '';
  const pubDate = d.pubDate || d.isoDate || d.date || d.published || '';
  const description = d.contentSnippet || d.content || d.description || d.summary || '';

  let source = d.creator || d.author || d['dc:creator'] || '';
  if (!source && title.includes(' - ')) {
    source = title.split(' - ').pop().trim();
  }
  if (!source && link) {
    try { source = new URL(link).hostname.replace('www.', ''); } catch(e) { source = 'غير معروف'; }
  }
  if (!source) source = 'غير معروف';

  const isOfficial = link.includes('gib.gov.tr') || link.includes('resmigazete.gov.tr') || link.includes('sgk.gov.tr') || link.includes('hmb.gov.tr') || title.includes('Resmi Gazete') || title.includes('tebliğ') || title.includes('teblig') || title.includes('sirküler') || title.includes('GİB') || title.includes('Gelir İdaresi');

  if (!title) continue;
  const normalizedTitle = title.toLowerCase().trim().replace(/\s+/g, ' ');
  if (seen.has(normalizedTitle)) continue;
  seen.add(normalizedTitle);

  if (pubDate) {
    const articleDate = new Date(pubDate);
    if (!isNaN(articleDate.getTime()) && articleDate < sevenDaysAgo) continue;
  }

  filtered.push({
    json: {
      title, description: description.substring(0, 500), link, source,
      sourceType: isOfficial ? 'رسمي' : 'إخباري',
      pubDate, collectedAt: now.toISOString()
    }
  });
}

filtered.sort((a, b) => {
  if (a.json.sourceType === 'رسمي' && b.json.sourceType !== 'رسمي') return -1;
  if (a.json.sourceType !== 'رسمي' && b.json.sourceType === 'رسمي') return 1;
  return new Date(b.json.pubDate || 0) - new Date(a.json.pubDate || 0);
});

const result = filtered.slice(0, 5);
if (result.length === 0) {
  return [{ json: { title: 'لا توجد أخبار جديدة', description: '', link: '', source: '', sourceType: '', pubDate: '', collectedAt: now.toISOString(), noNews: true } }];
}
return result;

// استخراج النص من HTML وتحضير طلب Gemini
const items = $input.all();
const originalItems = $('تنظيف وتصفية الأخبار').all();

return items.map((item, index) => {
  const original = originalItems[index]?.json || {};
  let html = item.json.data || item.json.body || '';
  if (typeof html !== 'string') html = JSON.stringify(html);

  // تنظيف HTML → نص عادي
  let articleText = html
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
    .replace(/<nav[^>]*>[\s\S]*?<\/nav>/gi, '')
    .replace(/<header[^>]*>[\s\S]*?<\/header>/gi, '')
    .replace(/<footer[^>]*>[\s\S]*?<\/footer>/gi, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/\s+/g, ' ')
    .trim();

  // أخذ أول 3000 حرف فقط (كافي للتحليل)
  articleText = articleText.substring(0, 3000);

  const title = original.title || '';
  const source = original.source || '';
  const sourceType = original.sourceType || '';

  const prompt = 'أنت محلل أخبار ضريبية تركية خبير ومتخصص. لديك خبر ضريبي ونص المقال الكامل. مطلوب منك:\n\n1. قراءة المقال بعناية واستخراج التفاصيل الدقيقة\n2. تحديد الأرقام والنسب والمواد القانونية المذكورة\n3. شرح التأثير العملي على الشركات في تركيا\n\nالعنوان: ' + title + '\nالمصدر: ' + source + ' (' + sourceType + ')\n\nنص المقال الكامل:\n' + articleText + '\n\nأجب بـ JSON فقط بهذا الشكل:\n{\n  "isRelevant": true/false,\n  "importance": "عالي/متوسط/منخفض",\n  "summaryAr": "ملخص تفصيلي بالعربي (3-5 جمل) يتضمن الأرقام والنسب والتفاصيل المحددة من المقال",\n  "summaryTr": "ملخص تفصيلي بالتركي (3-5 جمل)",\n  "category": "KDV/SGK/Kurumlar/e-Fatura/Muhtasar/Genel",\n  "suggestedTitle": "عنوان عربي جذاب ودقيق للنشر على السوشال ميديا",\n  "keyDetails": "أهم 3-5 نقاط محددة من الخبر (أرقام، نسب، مواعيد، مواد قانونية)",\n  "impactOnCompanies": "كيف يؤثر هذا على الشركات عملياً؟ ماذا يجب أن تفعل؟",\n  "legalReferences": "المواد القانونية والتبليغات المذكورة إن وجدت"\n}';

  const body = {
    contents: [{ parts: [{ text: prompt }] }],
    generationConfig: { temperature: 0.2 }
  };

  return {
    json: {
      ...original,
      articleText: articleText.substring(0, 500),
      geminiBody: body
    }
  };
});

const items = $input.all();
const originalItems = $('استخراج النص وتحضير Gemini').all();

return items.map((item, index) => {
  const original = originalItems[index]?.json || {};

  let analysis = {};
  try {
    const content = item.json.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
    const cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    analysis = JSON.parse(cleaned);
  } catch (e) {
    analysis = {
      isRelevant: true, importance: 'متوسط',
      summaryAr: original.description || '', summaryTr: '',
      category: 'Genel', suggestedTitle: original.title || '',
      keyDetails: '', impactOnCompanies: '', legalReferences: ''
    };
  }

  if (!analysis.isRelevant) return null;

  return {
    json: {
      title: original.title || '',
      suggestedTitle: analysis.suggestedTitle || '',
      summaryAr: analysis.summaryAr || '',
      summaryTr: analysis.summaryTr || '',
      keyDetails: analysis.keyDetails || '',
      impactOnCompanies: analysis.impactOnCompanies || '',
      legalReferences: analysis.legalReferences || '',
      category: analysis.category || 'Genel',
      importance: analysis.importance || 'متوسط',
      source: original.source || '',
      sourceType: original.sourceType || '',
      sourceUrl: original.link || '',
      pubDate: original.pubDate || '',
      collectedAt: original.collectedAt || new Date().toISOString(),
      approved: '',
      status: 'جديد'
    }
  };
}).filter(item => item !== null);
